import{getRandomBytesAsync}from"expo-random";import{urlAlphabet}from"../url-alphabet/index.js";let random=getRandomBytesAsync,customAlphabet=(o,t=21)=>{let a=(2<<31-Math.clz32(o.length-1|1))-1,l=Math.ceil(1.6*a*t/o.length),m=(n,r=t)=>random(l).then(t=>{let e=l;for(;e--;)if((n+=o[t[e]&a]||"").length===r)return n;return m(n,r)});return t=>m("",t)},nanoid=(n=21)=>random(n).then(t=>{let e="";for(;n--;)e+=urlAlphabet[63&t[n]];return e});export{nanoid,customAlphabet,random};